import asyncio
import json
import math
import time
from dataclasses import dataclass, asdict
from typing import Dict, List, Optional, Tuple

import websockets

TICK_RATE = 20
BROADCAST_RATE = 20
MAX_PLAYERS = 200
WORLD_SIZE = 10000.0


@dataclass
class PlayerState:
    player_id: str
    x: float
    y: float
    z: float
    yaw: float = 0.0
    pitch: float = 0.0
    vx: float = 0.0
    vy: float = 0.0
    vz: float = 0.0
    health: int = 100
    team: int = 0
    alive: bool = True
    last_seen: float = 0.0


class BattleRoyaleServer:
    def __init__(self):
        self.clients: Dict[websockets.WebSocketServerProtocol, str] = {}
        self.players: Dict[str, PlayerState] = {}
        self.next_player_num = 1
        self.lock = asyncio.Lock()
        self.running = True
        self._tick_task: Optional[asyncio.Task] = None
        self._broadcast_task: Optional[asyncio.Task] = None

    def _new_player_id(self) -> str:
        pid = f"p{self.next_player_num}"
        self.next_player_num += 1
        return pid

    async def register(self, ws: websockets.WebSocketServerProtocol) -> str:
        async with self.lock:
            if len(self.players) >= MAX_PLAYERS:
                raise RuntimeError("Server full")
            pid = self._new_player_id()
            self.clients[ws] = pid
            spawn_x = (len(self.players) * 37) % WORLD_SIZE
            spawn_y = (len(self.players) * 53) % WORLD_SIZE
            spawn_z = 0.0
            self.players[pid] = PlayerState(
                player_id=pid,
                x=spawn_x,
                y=spawn_y,
                z=spawn_z,
                last_seen=time.time(),
            )
            return pid

    async def unregister(self, ws: websockets.WebSocketServerProtocol):
        async with self.lock:
            pid = self.clients.pop(ws, None)
            if pid and pid in self.players:
                del self.players[pid]

    async def handle_message(self, ws: websockets.WebSocketServerProtocol, message: str):
        pid = self.clients.get(ws)
        if not pid:
            return
        try:
            data = json.loads(message)
        except json.JSONDecodeError:
            return

        msg_type = data.get("type")
        if msg_type == "input":
            dx = float(data.get("dx", 0.0))
            dy = float(data.get("dy", 0.0))
            dz = float(data.get("dz", 0.0))
            yaw = float(data.get("yaw", 0.0))
            pitch = float(data.get("pitch", 0.0))
            speed = float(data.get("speed", 8.0))

            async with self.lock:
                p = self.players.get(pid)
                if not p:
                    return
                p.yaw = yaw
                p.pitch = pitch
                p.vx = dx * speed
                p.vy = dy * speed
                p.vz = dz * speed
                p.last_seen = time.time()
        elif msg_type == "ping":
            await ws.send(json.dumps({"type": "pong", "t": time.time()}))
        elif msg_type == "state_request":
            await self.send_full_state(ws)

    async def send_full_state(self, ws: websockets.WebSocketServerProtocol):
        async with self.lock:
            payload = {
                "type": "full_state",
                "server_time": time.time(),
                "players": [asdict(p) for p in self.players.values()],
            }
        await ws.send(json.dumps(payload))

    async def broadcast_full_state(self):
        async with self.lock:
            payload = {
                "type": "full_state",
                "server_time": time.time(),
                "players": [asdict(p) for p in self.players.values()],
            }
            clients = list(self.clients.keys())
            message = json.dumps(payload)

        if not clients:
            return

        dead = []
        for ws in clients:
            try:
                await ws.send(message)
            except Exception:
                dead.append(ws)

        if dead:
            async with self.lock:
                for ws in dead:
                    pid = self.clients.pop(ws, None)
                    if pid and pid in self.players:
                        del self.players[pid]

    async def tick(self):
        dt = 1.0 / TICK_RATE
        while self.running:
            start = time.time()
            async with self.lock:
                now = time.time()
                for p in self.players.values():
                    if not p.alive:
                        continue
                    p.x = max(0.0, min(WORLD_SIZE, p.x + p.vx * dt))
                    p.y = max(0.0, min(WORLD_SIZE, p.y + p.vy * dt))
                    p.z = max(0.0, min(WORLD_SIZE, p.z + p.vz * dt))
                    p.last_seen = now
            elapsed = time.time() - start
            await asyncio.sleep(max(0.0, dt - elapsed))

    async def broadcaster(self):
        dt = 1.0 / BROADCAST_RATE
        while self.running:
            start = time.time()
            await self.broadcast_full_state()
            elapsed = time.time() - start
            await asyncio.sleep(max(0.0, dt - elapsed))

    async def handler(self, ws: websockets.WebSocketServerProtocol, path: str):
        try:
            pid = await self.register(ws)
            await ws.send(json.dumps({
                "type": "welcome",
                "player_id": pid,
                "server_time": time.time(),
            }))
            await self.send_full_state(ws)

            async for message in ws:
                await self.handle_message(ws, message)
        except Exception:
            pass
        finally:
            await self.unregister(ws)

    async def start(self, host: str = "0.0.0.0", port: int = 8765):
        self._tick_task = asyncio.create_task(self.tick())
        self._broadcast_task = asyncio.create_task(self.broadcaster())
        async with websockets.serve(self.handler, host, port, max_size=2**20):
            await asyncio.Future()


